sql:
SELECT attribute_name, change_reason
FROM pokemon_version_details
WHERE is_critical_change = 0;

external_knowledge:
; The Pokémon's generation refers to the generation in which the Pokémon was first introduced in the Pokémon franchise; 
; A Pokémon being 'legendary' means it is a rare and powerful Pokémon in the Pokémon franchise; 
; 'Damage relations' refers to how much damage a Pokémon type deals or receives from other types; 
; Media assets include images or other files associated with each Pokémon; 
; Access logs record interactions between users and Pokémon, including whether the access was successful.
